public enum ProcessedContent {
    
    case applicationMessage(plaintext: Data, sender: CredentialData
    )
    case proposal(proposal: ProposalInfo, proposalRef: ProposalRef
    )
    case stagedCommit(newEpoch: UInt64, 
        /**
